class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        int left = index, right = n - index - 1;
        int l = 1, r = maxSum;
        while (l < r) {
            int mid = l + (r - l + 1) / 2;
            if ((mid - 1) * mid / 2 + (mid - 1 - (mid - 1 - left)) * (mid - (mid - 1 - left)) / 2 + 
                (mid - 1) * mid / 2 + (mid - 1 - (mid - 1 - right)) * (mid - (mid - 1 - right)) / 2 <= maxSum) {
                l = mid;
            } else {
                r = mid - 1;
            }
        }
        return l;
    }
};
